typedef struct {
    int *q1, *q2;
    int s1, e1, s2, e2;
} StackUsingQueues;

StackUsingQueues* createStack() {
    StackUsingQueues* st = malloc(sizeof(StackUsingQueues));
    st->q1 = NULL; st->q2 = NULL;
    st->s1 = st->e1 = st->s2 = st->e2 = 0;
    return st;
}

void push(StackUsingQueues* st, int x) {
    st->q2 = realloc(st->q2, sizeof(int) * (st->e2 + 1));
    st->q2[st->e2++] = x;

    while (st->s1 < st->e1) {
        st->q2 = realloc(st->q2, sizeof(int) * (st->e2 + 1));
        st->q2[st->e2++] = st->q1[st->s1++];
    }

    int *tmpQ = st->q1; st->q1 = st->q2; st->q2 = tmpQ;
    int ts = st->s1; st->s1 = st->s2; st->s2 = ts;
    int te = st->e1; st->e1 = st->e2; st->e2 = te;
}

int pop(StackUsingQueues* st) {
    return st->q1[st->s1++];
}

int top(StackUsingQueues* st) {
    return st->q1[st->s1];
}

bool empty(StackUsingQueues* st) {
    return st->s1 == st->e1;
}

